    [Fact]
    public void LoadYamlInput()
    {
        string yamlData = """
role: user

""";

        var instance = AnthropicWireMessage.FromYaml(yamlData);

        Assert.NotNull(instance);
        Assert.Equal("user", instance.Role);
    }

    [Fact]
    public void LoadJsonInput()
    {
        string jsonData = """
{
  "role": "user"
}
""";

        var instance = AnthropicWireMessage.FromJson(jsonData);
        Assert.NotNull(instance);
        Assert.Equal("user", instance.Role);
    }

    [Fact]
    public void RoundtripJson()
    {
        // Test that FromJson -> ToJson -> FromJson produces equivalent data
        string jsonData = """
{
  "role": "user"
}
""";

        var original = AnthropicWireMessage.FromJson(jsonData);
        Assert.NotNull(original);

        var json = original.ToJson();
        Assert.False(string.IsNullOrEmpty(json));

        var reloaded = AnthropicWireMessage.FromJson(json);
        Assert.NotNull(reloaded);
        Assert.Equal("user", reloaded.Role);
    }

    [Fact]
    public void RoundtripYaml()
    {
        // Test that FromYaml -> ToYaml -> FromYaml produces equivalent data
        string yamlData = """
role: user

""";

        var original = AnthropicWireMessage.FromYaml(yamlData);
        Assert.NotNull(original);

        var yaml = original.ToYaml();
        Assert.False(string.IsNullOrEmpty(yaml));

        var reloaded = AnthropicWireMessage.FromYaml(yaml);
        Assert.NotNull(reloaded);
        Assert.Equal("user", reloaded.Role);
    }

    [Fact]
    public void ToJsonProducesValidJson()
    {
        string jsonData = """
{
  "role": "user"
}
""";

        var instance = AnthropicWireMessage.FromJson(jsonData);
